SELECT tld_name, total_registrations
FROM tlds
ORDER BY total_registrations DESC;

SELECT AVG(growth_rate) AS average_growth_rate
FROM tlds
WHERE region = 'Europe' AND industry = 'Finance';

SELECT tld_name
FROM tlds
WHERE total_registrations = (SELECT MIN(total_registrations) FROM tlds);

SELECT SUM(total_registrations) AS total_active_registrations
FROM tlds
WHERE status = 'Active' AND growth_rate > 5;

SELECT tld_name, total_registrations
FROM tlds
ORDER BY total_registrations DESC;
